# llama.cpp: put 20 layers on the GPU, the rest on CPU
./llama-cli -m model.gguf --n-gpu-layers 20 -p "Hello"

# Ollama: override num_gpu for one request via the API
curl http://localhost:11434/api/generate -d '{
  "model": "llama3",
  "prompt": "Hello",
  "options": { "num_gpu": 20 }
}'
